Here's a minimal API endpoint that accepts multiple image files plus a text description via multipart form data:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Increase the max request body size to 50MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (IFormFileCollection files, HttpRequest request) =>
{
    var description = request.Form["description"].ToString();

    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var allowedTypes = new[] { "image/jpeg", "image/png", "image/gif", "image/webp" };
    var uploaded = new List<string>();

    foreach (var file in files)
    {
        if (!allowedTypes.Contains(file.ContentType))
            return Results.BadRequest($"Invalid file type: {file.ContentType}");

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var path = Path.Combine("uploads", fileName);

        Directory.CreateDirectory("uploads");
        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);

        uploaded.Add(fileName);
    }

    return Results.Ok(new { description, uploadedFiles = uploaded });
})
.DisableAntiforgery()
.WithMetadata(new RequestFormLimitsAttribute
{
    MultipartBodyLengthLimit = 50 * 1024 * 1024
});

app.Run();
```

**Key points:**

- `IFormFileCollection` binds all files from the form regardless of field name.
- `request.Form["description"]` reads the text field from the same multipart form.
- `ConfigureKestrel` raises the request body limit (default is ~30MB).
- `RequestFormLimitsAttribute` raises the multipart-specific limit to match.
- `.DisableAntiforgery()` is needed for minimal APIs accepting forms without an antiforgery token.

**Example `curl` to test:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "files=@photo1.jpg" \
  -F "files=@photo2.png" \
  -F "description=Vacation photos"
```
